const posts = $input.all().map(i => i.json);

// Filter posts that don't already have schema injected
// We detect this by looking for application/ld+json in content
const postsNeedingSchema = posts.filter(p => {
  const content = p.content?.rendered || '';
  return !content.includes('application/ld+json');
});

console.log(`${posts.length} total posts | ${postsNeedingSchema.length} need schema`);

return postsNeedingSchema.map(post => {
  // Detect post type from content and title
  const content = (post.content?.rendered || '').toLowerCase();
  const title = (post.title?.rendered || '').toLowerCase();

  // Detect if it's an FAQ-heavy post
  const hasFaq = content.includes('<h2') && (
    content.includes('frequently asked') ||
    content.includes('what is') ||
    content.includes('how do') ||
    content.includes('?</h')
  );

  // Detect if it's a how-to post  
  const isHowTo = title.startsWith('how to') || title.includes('step-by-step') || title.includes('guide');

  // Detect if it's a product review/comparison
  const isProduct = title.includes('best ') || title.includes('review') || title.includes('template');

  return { json: {
    post_id: post.id,
    post_title: post.title?.rendered || '',
    post_url: post.link,
    post_slug: post.slug,
    post_excerpt: (post.excerpt?.rendered || '').replace(/<[^>]+>/g, '').trim().substring(0, 200),
    post_content: post.content?.rendered || '',
    post_date: post.date,
    post_modified: post.modified,
    is_faq: hasFaq,
    is_how_to: isHowTo,
    is_product_review: isProduct,
    schema_types_needed: [
      'Article',
      hasFaq ? 'FAQPage' : null,
      isHowTo ? 'HowTo' : null
    ].filter(Boolean)
  }};
});

// Build complete JSON-LD schema markup for this post
const post = $input.first().json;
const siteUrl = 'https://clearstackstudio.com';
const authorName = 'ClearStack Studio';
const orgName = 'ClearStack Studio';

const schemas = [];

// ── 1. ARTICLE SCHEMA (all posts) ───────────────────────
schemas.push({
  '@context': 'https://schema.org',
  '@type': 'Article',
  'headline': post.post_title,
  'description': post.post_excerpt,
  'url': post.post_url,
  'datePublished': post.post_date,
  'dateModified': post.post_modified || post.post_date,
  'author': {
    '@type': 'Organization',
    'name': authorName,
    'url': siteUrl
  },
  'publisher': {
    '@type': 'Organization',
    'name': orgName,
    'url': siteUrl,
    'logo': {
      '@type': 'ImageObject',
      'url': `${siteUrl}/wp-content/themes/clearstack/logo.png`
    }
  },
  'mainEntityOfPage': {
    '@type': 'WebPage',
    '@id': post.post_url
  }
});

// ── 2. FAQPAGE SCHEMA (posts with Q&A) ──────────────────
if (post.is_faq) {
  // Extract Q&A pairs from HTML content
  const content = post.post_content || '';
  const qaPairs = [];

  // Match h2/h3 questions followed by paragraphs
  const questionMatches = content.matchAll(/<h[23][^>]*>([^<]*\?[^<]*)<\/h[23]>\s*<p>([^<]+(?:<[^>]+>[^<]*<\/[^>]+>)*[^<]*)<\/p>/gi);

  for (const match of questionMatches) {
    const question = match[1].replace(/<[^>]+>/g, '').trim();
    const answer = match[2].replace(/<[^>]+>/g, '').trim();
    if (question && answer && question.includes('?')) {
      qaPairs.push({ question, answer });
    }
  }

  if (qaPairs.length > 0) {
    schemas.push({
      '@context': 'https://schema.org',
      '@type': 'FAQPage',
      'mainEntity': qaPairs.map(qa => ({
        '@type': 'Question',
        'name': qa.question,
        'acceptedAnswer': {
          '@type': 'Answer',
          'text': qa.answer.substring(0, 500)
        }
      }))
    });
  }
}

// ── 3. HOWTO SCHEMA (step-by-step posts) ────────────────
if (post.is_how_to) {
  const content = post.post_content || '';
  const steps = [];

  // Extract numbered steps or h2 sections
  const stepMatches = content.matchAll(/<h[23][^>]*>([^<]*(?:step|tip|method|way)[^<]*)<\/h[23]>\s*<p>([^<]+)<\/p>/gi);

  for (const match of stepMatches) {
    const stepName = match[1].replace(/<[^>]+>/g, '').trim();
    const stepText = match[2].replace(/<[^>]+>/g, '').trim();
    if (stepName && stepText) {
      steps.push({ name: stepName, text: stepText });
    }
  }

  if (steps.length > 0) {
    schemas.push({
      '@context': 'https://schema.org',
      '@type': 'HowTo',
      'name': post.post_title,
      'description': post.post_excerpt,
      'step': steps.map((s, i) => ({
        '@type': 'HowToStep',
        'position': i + 1,
        'name': s.name,
        'text': s.text
      }))
    });
  }
}

// ── 4. BREADCRUMB SCHEMA (all posts) ────────────────────
schemas.push({
  '@context': 'https://schema.org',
  '@type': 'BreadcrumbList',
  'itemListElement': [
    { '@type': 'ListItem', 'position': 1, 'name': 'Home', 'item': siteUrl },
    { '@type': 'ListItem', 'position': 2, 'name': 'Blog', 'item': `${siteUrl}/blog` },
    { '@type': 'ListItem', 'position': 3, 'name': post.post_title, 'item': post.post_url }
  ]
});

// Build the script tag(s)
const schemaHtml = schemas
  .map(s => `<script type="application/ld+json">${JSON.stringify(s, null, 2)}</script>`)
  .join('\n');

// Inject schema at the beginning of post content
const existingContent = post.post_content || '';
const updatedContent = schemaHtml + '\n' + existingContent;

return [{ json: {
  post_id: post.post_id,
  post_title: post.post_title,
  schema_types: post.schema_types_needed,
  schemas_injected: schemas.length,
  faq_entries: schemas.find(s => s['@type'] === 'FAQPage')?.mainEntity?.length || 0,
  howto_steps: schemas.find(s => s['@type'] === 'HowTo')?.step?.length || 0,
  updated_content: updatedContent,
  schema_html_preview: schemaHtml.substring(0, 200) + '...'
}}];
